module RefModule(
    adder,
    address,
    rst,
    clk,
);input clk;
input rst;
input [15:0] adder;
output [7:0] address;
reg   [15:0] count;
assign address[7:0] = count[15:8];
  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt) begin
    if (rst) begin
        count <= 0;
    end
    else
    begin
        count <= count + adder;    
    end
end
endmodule
